        // 3-D interactive (WebGL) surface.
import graph3;
        size(7cm);
        currentprojection=orthographic(5,4,3);
        real a=1.2,h=2.6;
        surface s=surface(new triple(pair t){return (a*cos(t.x), a*sin(t.x), t.y);},(0,0),(2pi,h),32,10);
        draw(s, rgb(0.35,0.70,0.90)+opacity(0.85), meshpen=rgb(0.10,0.35,0.50)+linewidth(0.2pt));
        draw(O--(2.0,0,0),gray,Arrow3); draw(O--(0,2.0,0),gray,Arrow3); draw(O--(0,0,3.2),gray,Arrow3);
        label("$x$",(2.0,0,0),S); label("$y$",(0,2.0,0),E); label("$z$",(0,0,3.2),N);

        // 3-D interactive (WebGL) surface.
import graph3;
        size(7cm);
        currentprojection=orthographic(5,4,3);
        real R=2;
        surface s=surface(new triple(pair t){real r=t.y; return (r*cos(t.x), r*sin(t.x), r);},(0,0),(2pi,R),32,12);
        draw(s, rgb(0.95,0.55,0.35)+opacity(0.85), meshpen=rgb(0.50,0.22,0.10)+linewidth(0.2pt));
        draw(O--(2.0,0,0),gray,Arrow3); draw(O--(0,2.0,0),gray,Arrow3); draw(O--(0,0,2.8),gray,Arrow3);
        label("$x$",(2.0,0,0),S); label("$y$",(0,2.0,0),E); label("$z$",(0,0,2.8),N);

image.latex-image:
\begin{tikzpicture}[scale=0.9, >=stealth]
    \draw[->] (0,0) -- (4.8,0) node[right] {\(x\)};
    \draw[->] (0,0) -- (-1.9,-1.2) node[left] {\(y\)};
    \draw[->] (0,0) -- (0,4.6) node[above] {\(z\)};

    \coordinate (O) at (0,0);
    \coordinate (Pxy) at (2.7,-0.7);
    \coordinate (P) at (2.7,3.0);

    \draw[dashed] (Pxy) -- (P);
    \draw[dashed] (O) -- (Pxy);
    \draw[->, very thick] (O) -- (P) node[midway, above left] {\(\rho\)};

    \draw[thick] (0,1.2) arc[start angle=90,end angle=48,radius=1.2];
    \node at (0.7,1.55) {\(\phi\)};

    \draw[thick] (0.9,0) arc[start angle=0,end angle=-14,x radius=1.0,y radius=0.32];
    \node at (1.35,-0.27) {\(\theta\)};

    \draw[->, thick] (O) -- (Pxy) node[midway, below] {\(\rho\sin\phi\)};
    \fill (P) circle (2.5pt);
    \fill (Pxy) circle (2pt);
    \node[right] at (P) {\((\rho,\theta,\phi)\)};
\end{tikzpicture}

subsection.p:
For converting from rectangular to spherical, the main formulas are
\boxed{ \rho^2=x^2+y^2+z^2, }
\boxed{ \tan\theta=\frac{y}{x} \quad\text{with the quadrant checked carefully}, }
and
\boxed{ \cos\phi=\frac{z}{\rho} \quad(\rho\neq0). }

As always, angle formulas need care. The equation
\tan\theta=\frac{y}{x}
does not determine the quadrant by itself.
